import com.spandigital.standings.domain.StandingsRanking;
import com.spandigital.standings.domain.TeamRecord;
import java.util.ArrayList;
import java.util.List;

public class ContractCheck {
    public static void main(String[] args) {
        StandingsRanking r = new StandingsRanking();
        List<TeamRecord> all = new ArrayList<>();
        String[] names = {"A", "B"};
        // small exhaustive grid: GF/GA 0..6, won 0..2, drawn 0..2, two names
        for (String n : names)
            for (int gf = 0; gf <= 6; gf++)
                for (int ga = 0; ga <= 6; ga++)
                    for (int w = 0; w <= 2; w++)
                        for (int d = 0; d <= 2; d++)
                            all.add(new TeamRecord(n, w + d, w, d, 0, gf, ga));
        System.out.println("records: " + all.size());
        long anti = 0, trans = 0;
        int n = all.size();
        int[][] sgn = new int[n][n];
        for (int i = 0; i < n; i++)
            for (int j = 0; j < n; j++)
                sgn[i][j] = Integer.signum(r.compare(all.get(i), all.get(j)));
        for (int i = 0; i < n; i++)
            for (int j = 0; j < n; j++)
                if (sgn[i][j] != -sgn[j][i]) { anti++; if (anti < 3) System.out.println("ANTISYM: " + all.get(i) + " vs " + all.get(j)); }
        for (int i = 0; i < n; i++)
            for (int j = 0; j < n; j++) {
                if (sgn[i][j] > 0) continue; // need a<=b
                for (int k = 0; k < n; k++) {
                    // a<b, b<c => a<c ; a==b => sgn(a,c)==sgn(b,c)
                    if (sgn[i][j] < 0 && sgn[j][k] < 0 && sgn[i][k] >= 0) { trans++; if (trans < 3) System.out.println("TRANS: " + all.get(i) + " < " + all.get(j) + " < " + all.get(k)); }
                    if (sgn[i][j] == 0 && sgn[i][k] != sgn[j][k]) { trans++; if (trans < 3) System.out.println("EQ-SUBST: " + all.get(i) + " == " + all.get(j) + " vs " + all.get(k)); }
                }
            }
        System.out.println("antisymmetry violations: " + anti);
        System.out.println("transitivity/substitutability violations: " + trans);
    }
}

